import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { authApi } from "../services/api";
import { useAuth } from "../context/AuthContext";

const Login = () => {
  const [form, setForm] = useState({ email: "", password: "" });
  const [error, setError] = useState("");
  const navigate = useNavigate();
  const { login } = useAuth();

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await authApi.login(form);
      login(res.data.access_token, res.data.user);
      navigate("/dashboard");
    } catch (err) {
      setError(err.response?.data?.detail || "Connexion échouée");
    }
  };

  return (
    <form className="max-w-md mx-auto bg-white p-6 rounded-xl shadow space-y-3" onSubmit={submit}>
      <h2 className="text-xl font-semibold">Connexion</h2>
      <input className="border p-2 rounded w-full" placeholder="Email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} />
      <input className="border p-2 rounded w-full" type="password" placeholder="Mot de passe" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} />
      {error && <p className="text-red-600 text-sm">{error}</p>}
      <button className="bg-primary text-white px-4 py-2 rounded">Se connecter</button>
    </form>
  );
};

export default Login;
